+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; factor: number; min: number};
+
+type Placement = {start: number; end: number};
+
+const tokenizeTracks = (template: string | undefined): string[] => {
+	if (!template) {
+		return [];
+	}
+
+	const tracks: string[] = [];
+	let current = '';
+	let depth = 0;
+
+	for (const character of template.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+		if (/\\s/.test(character) && depth === 0) {
+			if (current) tracks.push(current);
+			current = '';
+		} else {
+			current += character;
+		}
+	}
+
+	if (current) tracks.push(current);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {type: 'auto'};
+
+	const fixed = Number(value);
+	if (Number.isFinite(fixed) && fixed >= 0) return {type: 'fixed', size: fixed};
+
+	const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fr) return {type: 'fr', factor: Number(fr[1]), min: 0};
+
+	const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(fr)?\\s*\\)$/.exec(
+		value,
+	);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		const max = Number(minmax[2]);
+		return minmax[3]
+			? {type: 'fr', factor: max, min}
+			: {type: 'fixed', size: Math.max(min, max)};
+	}
+
+	return {type: 'auto'};
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value !== 'string') return undefined;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value.trim());
+	if (!match) return undefined;
+	const start = Number(match[1]) - 1;
+	const end = Number(match[2]) - 1;
+	return start >= 0 && end > start ? {start, end} : undefined;
+};
+
+const getGap = (node: DOMElement, gutter: 'column' | 'row'): number =>
+	gutter === 'column'
+		? (node.style.columnGap ?? node.style.gap ?? 0)
+		: (node.style.rowGap ?? node.style.gap ?? 0);
+
+const contentSize = (node: YogaNode, dimension: 'width' | 'height'): number => {
+	const edgeStart = dimension === 'width' ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
+	const edgeEnd = dimension === 'width' ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
+	const size =
+		dimension === 'width' ? node.getComputedWidth() : node.getComputedHeight();
+	return Math.max(
+		0,
+		size -
+			node.getComputedPadding(edgeStart) -
+			node.getComputedPadding(edgeEnd) -
+			node.getComputedBorder(edgeStart) -
+			node.getComputedBorder(edgeEnd),
+	);
+};
+
+const resolveTracks = (
+	tracks: Track[],
+	available: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const gapSize = Math.max(0, tracks.length - 1) * gap;
+	let used = gapSize;
+	let frTotal = 0;
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') {
+			used += track.size;
+			return track.size;
+		}
+		if (track.type === 'auto') {
+			const size = autoSizes[index] ?? 0;
+			used += size;
+			return size;
+		}
+		used += track.min;
+		frTotal += track.factor;
+		return track.min;
+	});
+
+	const remaining = Math.max(0, available - used);
+	if (frTotal > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.type === 'fr') sizes[index]! += (remaining * track.factor) / frTotal;
+		}
+	}
+
+	return sizes;
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const spanSize = (sizes: number[], start: number, end: number, gap: number) =>
+	sizes.slice(start, end).reduce((total, size) => total + size, 0) +
+	Math.max(0, end - start - 1) * gap;
+
+const resetGridLayout = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') resetGridLayout(child);
+	}
+
+	if (!node.internal_gridItem || !node.yogaNode) return;
+	const yogaNode = node.yogaNode;
+	yogaNode.setPositionType(
+		node.style.position === 'absolute'
+			? Yoga.POSITION_TYPE_ABSOLUTE
+			: node.style.position === 'static'
+				? Yoga.POSITION_TYPE_STATIC
+				: Yoga.POSITION_TYPE_RELATIVE,
+	);
+	for (const edge of [Yoga.EDGE_LEFT, Yoga.EDGE_TOP, Yoga.EDGE_RIGHT, Yoga.EDGE_BOTTOM]) {
+		yogaNode.setPosition(edge, undefined);
+	}
+	if (typeof node.style.width === 'number') yogaNode.setWidth(node.style.width);
+	else if (typeof node.style.width === 'string') yogaNode.setWidth(node.style.width);
+	else yogaNode.setWidthAuto();
+	if (typeof node.style.height === 'number') yogaNode.setHeight(node.style.height);
+	else if (typeof node.style.height === 'string') yogaNode.setHeight(node.style.height);
+	else yogaNode.setHeightAuto();
+	node.internal_gridItem = false;
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	if (node.style.display === 'grid' && node.yogaNode) {
+		const children = node.childNodes.filter(
+			(child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode),
+		);
+		const columnTracks = tokenizeTracks(node.style.gridTemplateColumns).map(parseTrack);
+		const columns = columnTracks.length > 0 ? columnTracks : [{type: 'auto'} as Track];
+		const rowTracks = tokenizeTracks(node.style.gridTemplateRows).map(parseTrack);
+		const columnGap = getGap(node, 'column');
+		const rowGap = getGap(node, 'row');
+		const placements: Array<{node: DOMElement; column: Placement; row: Placement}> = [];
+		const occupied = new Set<string>();
+		let cursor = 0;
+
+		for (const child of children) {
+			const column = parsePlacement(child.style.gridColumn);
+			const row = parsePlacement(child.style.gridRow);
+			let resolvedColumn = column;
+			let resolvedRow = row;
+			if (!resolvedColumn || !resolvedRow) {
+				while (occupied.has(`${Math.floor(cursor / columns.length)}:${cursor % columns.length}`)) cursor++;
+				resolvedColumn ??= {start: cursor % columns.length, end: (cursor % columns.length) + 1};
+				resolvedRow ??= {start: Math.floor(cursor / columns.length), end: Math.floor(cursor / columns.length) + 1};
+			}
+			for (let rowIndex = resolvedRow.start; rowIndex < resolvedRow.end; rowIndex++) {
+				for (let columnIndex = resolvedColumn.start; columnIndex < resolvedColumn.end; columnIndex++) occupied.add(`${rowIndex}:${columnIndex}`);
+			}
+			placements.push({node: child, column: resolvedColumn, row: resolvedRow});
+			cursor++;
+		}
+
+		const rowCount = Math.max(
+			rowTracks.length,
+			...placements.map(placement => placement.row.end),
+			1,
+		);
+		while (rowTracks.length < rowCount) rowTracks.push({type: 'auto'});
+
+		const columnAutoSizes = columns.map(() => 0);
+		const rowAutoSizes = rowTracks.map(() => 0);
+		for (const placement of placements) {
+			if (placement.column.end - placement.column.start === 1 && columns[placement.column.start]?.type === 'auto') {
+				columnAutoSizes[placement.column.start] = Math.max(columnAutoSizes[placement.column.start]!, placement.node.yogaNode!.getComputedWidth());
+			}
+			if (placement.row.end - placement.row.start === 1 && rowTracks[placement.row.start]?.type === 'auto') {
+				rowAutoSizes[placement.row.start] = Math.max(rowAutoSizes[placement.row.start]!, placement.node.yogaNode!.getComputedHeight());
+			}
+		}
+
+		const widths = resolveTracks(columns, contentSize(node.yogaNode, 'width'), columnGap, columnAutoSizes);
+		const heights = resolveTracks(rowTracks, contentSize(node.yogaNode, 'height'), rowGap, rowAutoSizes);
+		if (node.style.height === undefined) {
+			node.yogaNode.setHeight(heights.reduce((total, height) => total + height, 0) + Math.max(0, heights.length - 1) * rowGap + node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) + node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) + node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+		}
+		const columnOffsets = offsets(widths, columnGap);
+		const rowOffsets = offsets(heights, rowGap);
+		for (const placement of placements) {
+			const yogaNode = placement.node.yogaNode!;
+			yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+			yogaNode.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column.start]!);
+			yogaNode.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row.start]!);
+			yogaNode.setWidth(spanSize(widths, placement.column.start, placement.column.end, columnGap));
+			yogaNode.setHeight(spanSize(heights, placement.row.start, placement.row.end, rowGap));
+			placement.node.internal_gridItem = true;
+		}
+	}
+
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') layoutGrid(child);
+	}
+};
+
+export const calculateLayout = (rootNode: DOMElement, width?: number): void => {
+	resetGridLayout(rootNode);
+	if (width !== undefined) rootNode.yogaNode!.setWidth(width);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	for (let index = 0; index < 3; index++) {
+		layoutGrid(rootNode);
+		rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	}
+};
